/* ─── Dashboard Briefing ─── */

.dashboard-briefing {
    background: var(--bg-card);
    border: 1px solid var(--border-card);
    border-left: 3px solid var(--accent-amber);
    border-radius: 14px;
    box-shadow: var(--shadow-card-sm);
    width: 100%;
    margin-bottom: 16px;
    overflow: hidden;
}

/* ─── Header ─── */

.dashboard-briefing-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 14px 20px 0;
}

.dashboard-briefing-header-left {
    display: flex;
    align-items: center;
    gap: 10px;
}

.dashboard-briefing-title {
    font-family: 'Playfair Display', serif;
    font-size: 15px;
    font-weight: 600;
    color: var(--text-primary, #1a1a1a);
    margin: 0;
}

.dashboard-briefing-date {
    font-family: 'Outfit', sans-serif;
    font-size: 12px;
    color: var(--text-secondary, #a1a1aa);
    font-weight: 400;
}

.dashboard-briefing-toggle {
    background: none;
    border: none;
    cursor: pointer;
    color: var(--text-secondary, #a1a1aa);
    padding: 4px;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s ease, color 0.15s ease, transform 0.2s ease;
}

.dashboard-briefing-toggle:hover {
    background: rgba(0, 0, 0, 0.05);
    color: var(--text-primary, #1a1a1a);
}

.dashboard-briefing-toggle.is-collapsed {
    transform: rotate(-90deg);
}

/* ─── Content (stacked layout) ─── */

.dashboard-briefing-body {
    display: flex;
    flex-direction: column;
    padding: 14px 20px 16px;
    gap: 0;
}

/* ─── Divider ─── */

.dashboard-divider {
    height: 1px;
    background: var(--border-card);
    margin: 12px 0;
}

/* ─── Recap Section v2 ─── */

.dashboard-recap-v2 {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.recap-encouragement {
    font-family: 'Lora', serif;
    font-style: italic;
    font-size: 13.5px;
    color: var(--text-secondary, #a1a1aa);
    margin: 0;
    line-height: 1.5;
}

/* ─── Stat Tiles Grid ─── */

.recap-tiles-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 8px;
}

.recap-tile {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
    padding: 12px 6px 10px;
    background: var(--bg-secondary, #f5f5f5);
    border-radius: 10px;
    transition: background 0.15s ease, transform 0.15s ease;
}

.recap-tile:hover {
    background: var(--bg-hover, #ebebeb);
    transform: translateY(-1px);
}

.recap-tile-icon {
    color: var(--accent-amber, #f59e0b);
    opacity: 0.8;
    margin-bottom: 2px;
}

.recap-tile-value {
    font-family: 'Playfair Display', serif;
    font-size: 22px;
    font-weight: 700;
    color: var(--text-primary, #1a1a1a);
    font-variant-numeric: tabular-nums;
    line-height: 1.2;
}

.recap-tile-label {
    font-family: 'Outfit', sans-serif;
    font-size: 11px;
    text-transform: lowercase;
    color: var(--text-muted, #9ca3af);
    letter-spacing: 0.3px;
}

.recap-tile-micro {
    font-family: 'Lora', serif;
    font-size: 10px;
    font-style: italic;
    color: var(--accent-amber, #f59e0b);
    margin-top: 2px;
    text-align: center;
    line-height: 1.3;
}

/* ─── Best Post Card ─── */

.recap-best-post {
    display: flex;
    flex-direction: column;
    gap: 4px;
    padding: 12px 14px;
    background: linear-gradient(135deg, rgba(245, 158, 11, 0.08) 0%, rgba(245, 158, 11, 0.03) 100%);
    border: 1px solid rgba(245, 158, 11, 0.15);
    border-radius: 10px;
    cursor: pointer;
    transition: transform 0.15s ease, box-shadow 0.15s ease;
}

.recap-best-post:hover {
    transform: translateY(-1px);
    box-shadow: 0 2px 8px rgba(245, 158, 11, 0.12);
}

.recap-best-post-badge {
    font-family: 'Outfit', sans-serif;
    font-size: 10px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: var(--accent-amber, #f59e0b);
    display: flex;
    align-items: center;
    gap: 4px;
}

.recap-best-post-title {
    font-family: 'Lora', serif;
    font-size: 14px;
    color: var(--text-primary, #1a1a1a);
    line-height: 1.4;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.recap-best-post-stats {
    font-family: 'Outfit', sans-serif;
    font-size: 11px;
    color: var(--text-secondary, #a1a1aa);
}

/* ─── Community Highlights ─── */

.recap-community {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.recap-community-label {
    font-family: 'Outfit', sans-serif;
    font-size: 11px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.3px;
    color: var(--text-secondary, #a1a1aa);
}

.recap-community-item {
    display: flex;
    align-items: center;
    gap: 8px;
}

.recap-community-avatar {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
    flex-shrink: 0;
}

.recap-community-text {
    font-family: 'Outfit', sans-serif;
    font-size: 13px;
    color: var(--text-primary, #1a1a1a);
    line-height: 1.4;
}

.recap-community-text strong {
    font-weight: 600;
}

.recap-community-clickable {
    cursor: pointer;
    padding: 4px 6px;
    margin: -4px -6px;
    border-radius: 8px;
    transition: background 0.15s ease;
}

.recap-community-clickable:hover {
    background: var(--bg-hover, #ebebeb);
}

/* ─── Prompt Section ─── */

.dashboard-prompt {
    display: flex;
    flex-direction: column;
    gap: 10px;
}

.dashboard-prompt-header {
    display: flex;
    align-items: center;
    gap: 8px;
}

.dashboard-prompt-icon {
    opacity: 0.7;
    color: var(--accent-amber, #f59e0b);
    flex-shrink: 0;
}

.dashboard-prompt-label {
    font-family: 'Outfit', sans-serif;
    font-size: 11px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: var(--text-secondary, #a1a1aa);
}

.dashboard-prompt-category {
    font-size: 11px;
    padding: 2px 8px;
    border-radius: 10px;
    background: rgba(212, 168, 83, 0.12);
    color: var(--accent-amber, #f59e0b);
    margin-left: auto;
    font-weight: 500;
}

.dashboard-prompt-text {
    font-family: 'Lora', serif;
    font-size: 18px;
    font-weight: 600;
    line-height: 1.6;
    margin: 0;
    color: var(--text-primary, #1a1a1a);
    border-left: 3px solid var(--accent-amber, #f59e0b);
    padding-left: 14px;
}

.dashboard-prompt-footer {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
    margin-top: 2px;
}

.dashboard-prompt-write-btn {
    padding: 10px 24px;
    border-radius: 20px;
    border: none;
    background: var(--accent-amber, #f59e0b);
    color: #fff;
    font-family: 'Outfit', sans-serif;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s ease;
    box-shadow: 0 2px 8px rgba(245, 158, 11, 0.3);
    display: inline-flex;
    align-items: center;
}

.dashboard-prompt-write-btn:hover {
    background: var(--accent-amber-hover, #d97706);
    transform: translateY(-1px);
    box-shadow: 0 4px 12px rgba(245, 158, 11, 0.35);
}

.dashboard-prompt-write-btn:active {
    transform: translateY(0);
    box-shadow: 0 1px 4px rgba(245, 158, 11, 0.25);
}

.dashboard-prompt-responses {
    display: flex;
    align-items: center;
    gap: 8px;
    cursor: pointer;
    padding: 4px 8px;
    margin: -4px -8px;
    border-radius: 8px;
    transition: background 0.15s ease;
}

.dashboard-prompt-responses:hover {
    background: var(--bg-hover, #ebebeb);
}

.dashboard-prompt-avatars {
    display: flex;
}

.dashboard-prompt-avatar {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    border: 2px solid var(--bg-card, #fefefe);
    margin-left: -8px;
    object-fit: cover;
}

.dashboard-prompt-avatar:first-child {
    margin-left: 0;
}

.dashboard-prompt-count {
    font-size: 12px;
    color: var(--text-secondary, #a1a1aa);
}

/* ─── Mobile ─── */

@media (max-width: 480px) {
    .dashboard-briefing-body {
        padding: 12px 16px 14px;
    }

    .dashboard-briefing-header {
        padding: 12px 16px 0;
    }

    .dashboard-prompt-text {
        font-size: 15px;
    }

    .recap-tiles-grid {
        grid-template-columns: repeat(2, 1fr);
    }

    .recap-tile-value {
        font-size: 18px;
    }

    .recap-tile-micro {
        font-size: 9px;
    }
}

/* ─── Dark mode ─── */

[data-theme="dark"] .dashboard-briefing-toggle:hover {
    background: rgba(255, 255, 255, 0.08);
}

[data-theme="dark"] .dashboard-prompt-write-btn {
    background: var(--accent-amber, #f59e0b);
    color: #1a1a1a;
    box-shadow: 0 2px 8px rgba(245, 158, 11, 0.2);
}

[data-theme="dark"] .dashboard-prompt-write-btn:hover {
    background: var(--accent-amber-hover, #d97706);
    box-shadow: 0 4px 12px rgba(245, 158, 11, 0.25);
}

[data-theme="dark"] .recap-tile {
    background: var(--bg-secondary, #1e1e1e);
}

[data-theme="dark"] .recap-tile:hover {
    background: var(--bg-hover, #2a2a2a);
}

[data-theme="dark"] .recap-best-post {
    background: linear-gradient(135deg, rgba(245, 158, 11, 0.12) 0%, rgba(245, 158, 11, 0.04) 100%);
    border-color: rgba(245, 158, 11, 0.2);
}

[data-theme="dark"] .dashboard-prompt-responses:hover {
    background: rgba(255, 255, 255, 0.06);
}

/* ─── Prompt Responses Modal ─── */

.prompt-responses-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.4);
    backdrop-filter: blur(4px);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
    padding: 20px;
}

.prompt-responses-modal {
    background: var(--bg-elevated, #ffffff);
    border: 1px solid var(--border-card, #e5e5e5);
    border-radius: 16px;
    box-shadow: var(--shadow-modal, 0 8px 32px rgba(0, 0, 0, 0.12));
    width: 100%;
    max-width: 440px;
    max-height: 80vh;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.prompt-responses-header {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    padding: 18px 20px 14px;
    border-bottom: 1px solid var(--border-card, #e5e5e5);
    gap: 12px;
}

.prompt-responses-header-text {
    display: flex;
    flex-direction: column;
    gap: 4px;
    min-width: 0;
}

.prompt-responses-title {
    font-family: 'Playfair Display', serif;
    font-size: 16px;
    font-weight: 600;
    color: var(--text-heading, #1a1a1a);
    margin: 0;
}

.prompt-responses-prompt {
    font-family: 'Lora', serif;
    font-size: 12.5px;
    color: var(--text-secondary, #a1a1aa);
    margin: 0;
    line-height: 1.4;
    font-style: italic;
}

.prompt-responses-close {
    background: none;
    border: none;
    cursor: pointer;
    color: var(--text-secondary, #a1a1aa);
    padding: 4px;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    transition: background 0.15s ease, color 0.15s ease;
}

.prompt-responses-close:hover {
    background: rgba(0, 0, 0, 0.05);
    color: var(--text-primary, #1a1a1a);
}

.prompt-responses-list {
    overflow-y: auto;
    padding: 8px 12px 12px;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.prompt-response-card {
    display: flex;
    flex-direction: column;
    gap: 6px;
    padding: 12px 14px;
    border-radius: 10px;
    cursor: pointer;
    transition: background 0.15s ease;
}

.prompt-response-card:hover {
    background: var(--bg-hover, #f5f5f5);
}

.prompt-response-author {
    display: flex;
    align-items: center;
    gap: 8px;
}

.prompt-response-avatar-wrap {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    flex-shrink: 0;
}

.prompt-response-avatar-wrap.pr-ring-legend {
    border: 2px solid #FFD700;
    box-shadow:
        0 0 6px 1px rgba(255, 215, 0, 0.5),
        0 0 12px 2px rgba(255, 215, 0, 0.35),
        0 0 20px 4px rgba(255, 215, 0, 0.2);
    animation: pr-glow-legend 2s ease-in-out infinite alternate;
}

.prompt-response-avatar-wrap.pr-ring-og {
    border: 2px solid #9B59FF;
    box-shadow:
        0 0 6px 1px rgba(155, 89, 255, 0.5),
        0 0 12px 2px rgba(155, 89, 255, 0.35),
        0 0 20px 4px rgba(155, 89, 255, 0.2);
    animation: pr-glow-og 2s ease-in-out infinite alternate;
}

@keyframes pr-glow-legend {
    from {
        box-shadow:
            0 0 6px 1px rgba(255, 215, 0, 0.5),
            0 0 12px 2px rgba(255, 215, 0, 0.35),
            0 0 20px 4px rgba(255, 215, 0, 0.2);
    }
    to {
        box-shadow:
            0 0 8px 2px rgba(255, 215, 0, 0.6),
            0 0 16px 4px rgba(255, 215, 0, 0.4),
            0 0 24px 6px rgba(255, 215, 0, 0.25);
    }
}

@keyframes pr-glow-og {
    from {
        box-shadow:
            0 0 6px 1px rgba(155, 89, 255, 0.5),
            0 0 12px 2px rgba(155, 89, 255, 0.35),
            0 0 20px 4px rgba(155, 89, 255, 0.2);
    }
    to {
        box-shadow:
            0 0 8px 2px rgba(155, 89, 255, 0.6),
            0 0 16px 4px rgba(155, 89, 255, 0.4),
            0 0 24px 6px rgba(155, 89, 255, 0.25);
    }
}

.prompt-response-avatar {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    border: none;
    object-fit: cover;
    display: block;
}

.prompt-response-name {
    font-family: 'Outfit', sans-serif;
    font-size: 13px;
    font-weight: 600;
    color: var(--text-primary, #1a1a1a);
}

.prompt-response-title {
    font-family: 'Lora', serif;
    font-size: 14px;
    color: var(--text-primary, #1a1a1a);
    line-height: 1.4;
    margin: 0;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.prompt-response-time {
    font-family: 'Outfit', sans-serif;
    font-size: 11px;
    color: var(--text-muted, #9ca3af);
}

/* ─── See More Button ─── */

.prompt-responses-see-more {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 100%;
    padding: 10px;
    margin-top: 4px;
    border: none;
    border-radius: 8px;
    background: var(--bg-secondary, #f5f5f5);
    color: var(--text-secondary, #a1a1aa);
    font-family: 'Outfit', sans-serif;
    font-size: 13px;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s ease, color 0.15s ease;
    min-height: 38px;
}

.prompt-responses-see-more:hover:not(:disabled) {
    background: var(--bg-hover, #ebebeb);
    color: var(--text-primary, #1a1a1a);
}

.prompt-responses-see-more:disabled {
    cursor: default;
    opacity: 0.7;
}

/* ─── Modal Mobile ─── */

@media (max-width: 480px) {
    .prompt-responses-overlay {
        padding: 12px;
        align-items: flex-end;
    }

    .prompt-responses-modal {
        max-height: 70vh;
